// Moves mdBook's built-in controls (sidebar toggle, theme switcher, search) out of
// the default #menu-bar and into the Breez brand header rendered by theme/header.hbs,
// so the whole design reads as a single top bar. The controls keep working because
// book.js binds its listeners to the elements themselves, not to their position.
//
// index.hbs is regenerated by mdbook-pagetoc on every build, so the header cannot be
// baked into it; this runs at load time instead. brand-header.js is listed last in
// additional-js, so book.js has already wired every control by the time this fires.
(function () {
    function relocate() {
        var controls = document.getElementById("brand-controls");
        if (!controls) {
            return;
        }
        ["sidebar-toggle", "theme-toggle", "theme-list", "search-toggle"].forEach(function (id) {
            var el = document.getElementById(id);
            if (el) {
                controls.appendChild(el);
            }
        });
        markActiveNav();
    }

    // Highlight the current top-level section link (Home / GitHub) when it matches.
    function markActiveNav() {
        var here = window.location.href;
        document.querySelectorAll("#brand-header .brand-nav a").forEach(function (a) {
            if (a.href && here.indexOf(a.href) === 0) {
                a.classList.add("is-active");
            }
        });
    }

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", relocate);
    } else {
        relocate();
    }
})();
